// Update category counts
categories.forEach(cat => {
  cat.count = capsules.filter(c => c.category === cat.id).length;
});

export function getCapsulesByCategory(categoryId: string): Capsule[] {
  return capsules.filter(c => c.category === categoryId);
}

export function getCapsulesBySection(categoryId: string, sectionId: string): Capsule[] {
  return capsules.filter(c => c.category === categoryId && c.section === sectionId);
}

export function getPopularCapsules(): Capsule[] {
  return capsules.filter(c => c.popular);
}

export function getNewCapsules(): Capsule[] {
  return capsules.filter(c => c.isNew);
}

export function getRandomCapsule(): Capsule {
  return capsules[Math.floor(Math.random() * capsules.length)];
}

export function searchCapsules(query: string): Capsule[] {
  const q = query.toLowerCase();
  return capsules.filter(c =>
    c.titleUa.toLowerCase().includes(q) ||
    c.titleEn.toLowerCase().includes(q) ||
    c.descUa.toLowerCase().includes(q) ||
    c.descEn.toLowerCase().includes(q)
  );
}

// Localized getters
export function getLocalizedTitle(c: Capsule, lang: "ua" | "en"): string {
  return lang === "en" ? c.titleEn : c.titleUa;
}

export function getLocalizedDesc(c: Capsule, lang: "ua" | "en"): string {
  return lang === "en" ? c.descEn : c.descUa;
}

export function getLocalizedIntro(c: Capsule, lang: "ua" | "en"): string {
  return lang === "en" ? c.introEn : c.introUa;
}

export function getLocalizedTheory(c: Capsule, lang: "ua" | "en"): string {
  return lang === "en" ? c.theoryEn : c.theoryUa;
}

export function getLocalizedSimple(c: Capsule, lang: "ua" | "en"): string {
  return lang === "en" ? c.simpleEn : c.simpleUa;
}

export function getLocalizedFacts(c: Capsule, lang: "ua" | "en"): string[] {
  return lang === "en" ? c.factsEn : c.factsUa;
}

export function getLocalizedQuiz(c: Capsule, lang: "ua" | "en") {
  return lang === "en" ? c.quizEn : c.quizUa;
}

export function getLocalizedCategoryName(cat: Category, lang: "ua" | "en"): string {
  return lang === "en" ? cat.nameEn : cat.nameUa;
}

export function getLocalizedSectionName(sec: CategorySection, lang: "ua" | "en"): string {
  return lang === "en" ? sec.nameEn : sec.nameUa;
}

export function getLocalizedDifficulty(diff: string, lang: "ua" | "en"): string {
  if (lang === "ua") return diff;
  const map: Record<string, string> = { "базовий": "basic", "середній": "medium", "поглиблений": "advanced", "олімпіадний": "olympic" };
  return map[diff] || diff;
}
